import { graphql, Link } from "gatsby"
import React from "react"
import Layout from "../components/Layout"
import Seo from "../components/seo"

// SitePageContextл°ЬлґАнД∞ contextл•Љ мЭімЪ©нХі м†ДлЛђнХЬ к∞ТлУ§мЭШ typeмЭД мЦїмЭД мИШ мЮИлЛ§.

const Category = ({ data, location, pageContext }) => {
  const { title } = data.site.siteMetadata
  const { category } = pageContext // gatsby-node.jsмЭШ createPageмЧРмДЬ лД£мЦім§А мєінЕМк≥†л¶ђ мЭіл¶Д.
  const { edges, totalCount } = data.allMarkdownRemark
  const tagHeader = `${totalCount} post${totalCount === 1 ? "" : "s"
    } in "${category}"`

  return (
    <div className="category-page">
      <Layout location={location} title={title}>
        <Seo title={title} />
        <h1 className="header">{tagHeader}</h1>
        <ul>
          {/* к∞Б мєінЕМк≥†л¶ђмЧР нХілЛєнХШлКФ нПђмК§нКЄмЭШ л™©л°ЭмЭД мґЬл†•нХЬлЛ§. */}
          {edges.map(({ node }) => {
            const { slug } = node.fields
            const { title } = node.frontmatter
            return (
              <li key={slug}>
                <Link to={slug}>{title}</Link>
              </li>
            )
          })}
        </ul>
        <Link to="/">Go back to the homepage</Link>
      </Layout>
    </div>
  )
}

export default Category

// мњЉл¶ђмЭШ argumentмЭЄ $categoryлКФ page contextл°Ь м†ДлЛђ л∞ЫлКФлЛ§.
export const pageQuery = graphql`
  query Category($category: String) {
    site {
      siteMetadata {
        title
      }
    }
    allMarkdownRemark(
      limit: 2000
      sort: { fields: [frontmatter___date], order: DESC }
      filter: { frontmatter: { categories: { in: [$category] } } }
    ) {
      totalCount
      edges {
        node {
          fields {
            slug
          }
          frontmatter {
            title
          }
        }
      }
    }
  }
`